    public Object parseMarket(Object entry)
    {
        Object id = this.safeString(entry, "name");
        Object baseId = this.safeString(entry, "numerator");
        Object quoteId = this.safeString(entry, "denominator");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object filters = this.safeList(entry, "filters", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object minPrice = null;
        Object maxPrice = null;
        Object minAmount = null;
        Object maxAmount = null;
        Object minCost = null;
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(filters)); j++)
        {
            Object filter = Helpers.GetValue(filters, j);
            Object filterType = this.safeString(filter, "filterType");
            if (Helpers.isTrue(Helpers.isEqual(filterType, "PRICE_FILTER")))
            {
                minPrice = this.safeNumber(filter, "minPrice");
                maxPrice = this.safeNumber(filter, "maxPrice");
                minAmount = this.safeNumber(filter, "minAmount");
                maxAmount = this.safeNumber(filter, "maxAmount");
                minCost = this.safeNumber(filter, "minExchangeValue");
            }
        }
        Object status = this.safeString(entry, "status");
        final Object finalBase = base;
        final Object finalStatus = status;
        final Object finalMinAmount = minAmount;
        final Object finalMaxAmount = maxAmount;
        final Object finalMinPrice = minPrice;
        final Object finalMaxPrice = maxPrice;
        final Object finalMinCost = minCost;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", false );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "active", (Helpers.isEqual(finalStatus, "TRADING")) );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", BtcturkCore.this.parseNumber(BtcturkCore.this.parsePrecision(BtcturkCore.this.safeString(entry, "numeratorScale"))) );
                put( "price", BtcturkCore.this.parseNumber(BtcturkCore.this.parsePrecision(BtcturkCore.this.safeString(entry, "denominatorScale"))) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", finalMinAmount );
                    put( "max", finalMaxAmount );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", finalMinPrice );
                    put( "max", finalMaxPrice );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", finalMinCost );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", entry );
        }};
    }

    public Object parseBalance(Object response)
    {
        Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object entry = Helpers.GetValue(data, i);
            Object currencyId = this.safeString(entry, "asset");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(entry, "balance"));
            Helpers.addElementToObject(account, "free", this.safeString(entry, "free"));
            Helpers.addElementToObject(account, "used", this.safeString(entry, "locked"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

